function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function safeBool(v) {
  if (v === true) return true;
  if (typeof v === 'string') return v.trim().toLowerCase() === 'true';
  return false;
}
function hasValidAnalysis(row) {
  const aj = safeStr(row.analysisJson);
  if (!aj || aj === '{}' || aj === 'null') return false;
  try {
    const parsed = JSON.parse(aj);
    return parsed && typeof parsed === 'object' && !Array.isArray(parsed);
  } catch (e) { return false; }
}

const BLOCKED_STATUS = new Set([
  'needs_summary', 'analysis_error', 'summary_input_error', 'summary_parse_error'
]);

const items = $input.all();

return items.filter(item => {
  const j = item.json || {};
  const status = safeStr(j.status);

  if (BLOCKED_STATUS.has(status)) return false;
  if (!hasValidAnalysis(j)) return false;
  if (safeBool(j.wordpressPosted)) return false;
  if (!safeStr(j.vorgangKey)) return false;

  return true;
});

function safe(v) { return v === null || v === undefined ? '' : String(v).trim(); }

function parseVorgangsnummer(v) {
  const s = safe(v);
  const m = s.match(/^(\d{4})\/(\d+)(?:-(\d+))?/);
  if (!m) return { year: Infinity, main: Infinity, sub: 0 };
  return { year: parseInt(m[1], 10), main: parseInt(m[2], 10), sub: m[3] ? parseInt(m[3], 10) : 0 };
}

const items = $input.all();

items.sort((a, b) => {
  const ja = a.json || {};
  const jb = b.json || {};
  const va = parseVorgangsnummer(ja.vorgangsnummer);
  const vb = parseVorgangsnummer(jb.vorgangsnummer);
  if (va.year !== vb.year) return va.year - vb.year;
  if (va.main !== vb.main) return va.main - vb.main;
  if (va.sub !== vb.sub) return va.sub - vb.sub;
  return safe(ja.vorgangKey).localeCompare(safe(jb.vorgangKey));
});

return items;

function safeStr(v) { return v === null || v === undefined ? '' : String(v).trim(); }
function parseArray(v) {
  if (Array.isArray(v)) return v.map(x => safeStr(x)).filter(Boolean);
  const s = safeStr(v);
  if (!s) return [];
  try {
    const p = JSON.parse(s);
    if (Array.isArray(p)) return p.map(x => safeStr(x)).filter(Boolean);
  } catch (e) {}
  return s.split(/\s*\|\s*|\n+/).map(x => safeStr(x)).filter(Boolean);
}

const j = $input.item.json || {};

const title = safeStr(j.title);
const vorgangsnummer = safeStr(j.vorgangsnummer);
const summaryText = safeStr(j.summaryText);
const allrisUrl = safeStr(j.allrisUrl) || safeStr(j.sourceUrl);

let summaryMessage = safeStr(j.summaryMessage);
if (!summaryMessage && summaryText) {
  summaryMessage =
    'Neue ALLRIS-Vorlage\n\n' +
    'Titel:\n' + title + '\n\n' +
    'Vorgangsnummer:\n' + vorgangsnummer + '\n\n' +
    'Link:\n' + allrisUrl + '\n\n' +
    'Kurzfassung:\n' + summaryText + '\n\n' +
    'Einordnung:\n' +
    '- Thema: ' + (safeStr(j.thema) || '-') + '\n' +
    '- Betroffene: ' + (parseArray(j.betroffene).join(', ') || '-') + '\n' +
    '- Kosten/Haushalt: ' + (safeStr(j.kostenHaushalt) || '-') + '\n' +
    '- Buergerwirkung: ' + (safeStr(j.buergerwirkung) || '-');
}

const missing = [];
if (!safeStr(j.vorgangKey)) missing.push('vorgangKey');
if (!title) missing.push('title');
if (!vorgangsnummer) missing.push('vorgangsnummer');
if (!summaryText) missing.push('summaryText');
if (!summaryMessage) missing.push('summaryMessage');

const wordpressInputOk = missing.length === 0;

return {
  json: {
    ...j,
    summaryMessage: summaryMessage,
    _wordpressInputOk: wordpressInputOk,
    wordpressPostError: missing.length
      ? ('WordPress-Eingang unvollstaendig fuer ' + (safeStr(j.vorgangKey) || 'unbekannten Vorgang') + ': ' + missing.join(', ') + '.')
      : ''
  }
};

var title = $json.title || "";
var vorgangsnummer = String($json.vorgangsnummer || "").trim();
var link = $json.allrisUrl || $json.sourceUrl || "";
var summaryMessage = $json.summaryMessage || "";

// ── WordPress-Schutzprüfung (B5) ─────────────────────────────────────────────
var _wpHttpErrRE = /^\s*(?:400[\s:-]+bad\s+request|401[\s:-]+unauthorized|403[\s:-]+forbidden|404[\s:-]+not\s+found|408[\s:-]+request\s+time[- ]?out|429[\s:-]+too\s+many\s+requests|500[\s:-]+internal\s+server\s+error|501[\s:-]+not\s+implemented|502[\s:-]+bad\s+gateway|503[\s:-]+service\s+unavailable|504[\s:-]+gateway\s*time[- ]?out)\s*$/i;
var _wpErrorPattern = /gateway\s*time[- ]?out|bad\s+gateway|service\s+unavailable|internal\s+server\s+error|request\s+time[- ]?out|upstream\s+timed\s+out|proxy\s+error|temporarily\s+unavailable|too\s+many\s+requests|serverfehler|nginx\s+error|cloudflare\s+error/i;
if (!vorgangsnummer || !/^\d{4}\/\d+(?:-\d+)?$/.test(vorgangsnummer)) {
  throw new Error("WordPress-Veröffentlichung blockiert: ungültiger Titel oder ungültige Vorgangsnummer. Vorgangsnummer: \"" + vorgangsnummer + "\"");
}
if (!title || _wpHttpErrRE.test(title) || _wpErrorPattern.test(title)) {
  throw new Error("WordPress-Veröffentlichung blockiert: ungültiger Titel oder ungültige Vorgangsnummer. Titel: \"" + title + "\"");
}
if (!summaryMessage) {
  throw new Error("WordPress-Veröffentlichung blockiert: fehlende Zusammenfassung.");
}
// ── Ende WordPress-Schutzprüfung ─────────────────────────────────────────────


// BUG 1 BEHOBEN: esc() gibt echte HTML-Entities als ASCII-Strings zurueck,
// nicht als HTML-Entities im JS-Quelltext (die wuerden den String zerstoeren)
function esc(value) {
  return String(value != null ? value : "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

// BUG 2 BEHOBEN: attrEsc gibt &quot; als ASCII zurueck, nicht als HTML-Entity
function attrEsc(value) {
  return esc(value).replace(/"/g, "&quot;");
}

// BUG 3 BEHOBEN: eckige Klammern [ und ] innerhalb einer Regex-Zeichenklasse
// muessen escaped werden: \[ und \]
function escapeRegExp(value) {
  return String(value != null ? value : "").replace(/[\\^$.*+?()\[\]{}|]/g, "\\$&");
}

function cleanText(value) {
  return String(value != null ? value : "")
    .replace(/\r/g, "")
    .replace(/[ \t]+/g, " ")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function cleanTitle(value) {
  return cleanText(value)
    .replace(/^📄\s*/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function slugify(value) {
  return String(value != null ? value : "")
    .toLowerCase()
    .replace(/ä/g, "ae")
    .replace(/ö/g, "oe")
    .replace(/ü/g, "ue")
    .replace(/ß/g, "ss")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .slice(0, 95);
}

function cleanListItem(value) {
  return String(value != null ? value : "")
    .replace(/\r/g, "")
    .trim()
    .replace(/^(?:\s*(?:[-*\u2022\u25cf\u27a3\u25aa\u25e6]|\d+[.)])\s*)+/g, "")
    .replace(/\s+/g, " ")
    .trim();
}

function firstSentences(text, maxSentences, maxChars) {
  maxSentences = maxSentences != null ? maxSentences : 2;
  maxChars = maxChars != null ? maxChars : 320;
  var clean = cleanText(text);
  if (!clean) return "";
  var sentences = clean.match(/[^.!?]+[.!?]+/g);
  var result = sentences ? sentences.slice(0, maxSentences).join(" ") : clean;
  result = cleanText(result);
  if (result.length > maxChars) {
    result = result.slice(0, maxChars).replace(/\s+\S*$/, "") + " \u2026";
  }
  return result;
}

function extractSection(text, heading, nextHeadings) {
  nextHeadings = nextHeadings || [];
  var source = String(text || "").replace(/\r/g, "");
  var escapedHeading = escapeRegExp(heading);
  var pattern;
  if (nextHeadings.length > 0) {
    var nextPattern = nextHeadings.map(escapeRegExp).join("|");
    pattern = escapedHeading + ":\\s*([\\s\\S]*?)(?=\\n\\s*(?:" + nextPattern + "):|$)";
  } else {
    pattern = escapedHeading + ":\\s*([\\s\\S]*)";
  }
  var regex = new RegExp(pattern, "i");
  var match = source.match(regex);
  return match ? cleanText(match[1]) : "";
}

function extractEinordnungValue(text, label) {
  var source = String(text || "").replace(/\r/g, "");
  var escapedLabel = escapeRegExp(label);
  var pattern = "(?:^|\\n)\\s*[-*\\u2022\\u25cf\\u27a3\\u25aa\\u25e6]?\\s*" + escapedLabel + ":\\s*([^\\n]+)";
  var regex = new RegExp(pattern, "i");
  var match = source.match(regex);
  return match ? cleanText(match[1]) : "";
}

// BUG 4 BEHOBEN: Markdown-Backtick-Bloecke (``` ... ```) aus parseArrayLike entfernt.
// Die waren aus einem Markdown-Codeblock reinkopiert worden und sind kein gueltiges JS.
function parseArrayLike(value) {
  if (value === null || value === undefined || value === "") return [];
  if (Array.isArray(value)) {
    return value.map(cleanListItem).filter(Boolean);
  }
  if (typeof value === "string") {
    var raw = value.trim();
    if (!raw) return [];
    try {
      var parsed = JSON.parse(raw);
      if (Array.isArray(parsed)) {
        return parsed.map(cleanListItem).filter(Boolean);
      }
    } catch (e) {}
    return raw
      .split(/\n|\s+\|\s+|;/)
      .map(cleanListItem)
      .filter(Boolean);
  }
  return [cleanListItem(value)].filter(Boolean);
}

function extractBulletSection(text, sectionLabel, stopLabels) {
  stopLabels = stopLabels || [];
  var source = String(text || "").replace(/\r/g, "");
  var escapedSection = escapeRegExp(sectionLabel);
  var pattern;
  if (stopLabels.length > 0) {
    var stopPattern = stopLabels.map(escapeRegExp).join("|");
    pattern = escapedSection + ":\\s*([\\s\\S]*?)(?=\\n\\s*[-*\\u2022\\u25cf\\u27a3\\u25aa\\u25e6]?\\s*(?:" + stopPattern + "):|$)";
  } else {
    pattern = escapedSection + ":\\s*([\\s\\S]*)";
  }
  var regex = new RegExp(pattern, "i");
  var match = source.match(regex);
  if (!match) return [];
  return match[1]
    .split("\n")
    .map(cleanListItem)
    .filter(Boolean);
}

function listHtml(value, fallback) {
  fallback = fallback || "Keine konkreten Angaben vorhanden.";
  var arr = parseArrayLike(value);
  if (!arr.length) {
    return "<p>" + esc(fallback) + "</p>";
  }
  return "<ul>" + arr.map(function(item) {
    return "<li>" + esc(cleanListItem(item)) + "</li>";
  }).join("") + "</ul>";
}

function paragraphHtml(text) {
  var clean = cleanText(text);
  if (!clean) {
    return "<p>Keine konkreten Angaben vorhanden.</p>";
  }
  return clean
    .split(/\n{2,}/)
    .map(function(block) {
      return "<p>" + esc(block).replace(/\n/g, "<br>") + "</p>";
    })
    .join("\n");
}

function formatValue(value) {
  var arr = parseArrayLike(value);
  if (arr.length > 1) return arr.join(", ");
  if (arr.length === 1) return arr[0];
  return "";
}

function uniqueTags(tags) {
  return Array.from(new Set(
    tags
      .map(function(t) { return cleanText(t); })
      .filter(Boolean)
      .filter(function(t) { return t.length <= 50; })
  ));
}

function topicTagsFromText(text) {
  var t = String(text || "").toLowerCase();
  var tags = [];

  function hasAny(words) {
    return words.some(function(word) {
      return t.indexOf(String(word).toLowerCase()) !== -1;
    });
  }

  if (hasAny(["bus", "stadtbus", "linie", "liniennetz", "haltestelle", "oepnv", "\u00f6pnv", "fahrplan", "verkehr", "umleitung", "sperrung", "radweg", "parkplatz"])) {
    tags.push("Verkehr", "\u00d6PNV");
  }
  if (hasAny(["bauschutt", "baustelle", "bauzaun", "abbruch", "abriss", "baustellensicherheit", "absperrung"])) {
    tags.push("Baustelle", "Sicherheit");
  }
  if (hasAny(["stadtbus", "haltestelle", "fahrgast", "fahrgäste", "linienfuehrung", "schuljahresbeginn"])) {
    tags.push("Stadtbus");
  }
  if (hasAny(["denkmalschutz", "altstadt", "unesco", "welterbe", "denkmal", "sanierung", "historisch"])) {
    tags.push("Altstadt", "Denkmalschutz", "UNESCO");
  }
  if (hasAny(["haushalt", "kosten", "finanz", "haushaltsmittel", "foerderung", "investition", "geb\u00fchr", "zuschuss"])) {
    tags.push("Haushalt", "Finanzen", "Kosten");
  }
  if (hasAny(["schule", "sch\u00fcler", "sch\u00fclerinnen", "kita", "kindergarten", "bildung", "jugend", "schulweg"])) {
    tags.push("Schule", "Bildung");
  }
  if (hasAny(["m\u00fclleimer", "papierkorb", "abfall", "b\u00e4nke", "bank", "sitzbank", "stadtbild", "aufenthaltsqualit\u00e4t", "innenstadt", "standort"])) {
    tags.push("Stadtbild", "Aufenthaltsqualit\u00e4t");
  }
  if (hasAny(["digitalisierung", "software", "open source", "verwaltung", "transparenz", "daten", "portal", "online", "it"])) {
    tags.push("Verwaltung", "Digitalisierung", "Transparenz");
  }
  if (hasAny(["energie", "w\u00e4rme", "w\u00e4rmeplanung", "klima", "klimaschutz", "heizung", "w\u00e4rmenetz", "fernw\u00e4rme"])) {
    tags.push("Energie", "W\u00e4rmeplanung", "Klimaschutz");
  }
  if (hasAny(["barriere", "barrierefreiheit", "inklusion", "teilhabe", "behinderung", "senioren", "\u00e4ltere menschen"])) {
    tags.push("Barrierefreiheit", "Inklusion");
  }
  if (hasAny(["wahl", "wahlwerbung", "plakat", "plakate", "sondernutzung", "wahlvorschlag", "kandidierende", "einzelbewerbung", "chancengleichheit"])) {
    tags.push("Wahl", "Wahlwerbung", "Chancengleichheit");
  }
  return tags;
}

var extractedKurzfassung = extractSection(summaryMessage, "Kurzfassung", [
  "Einordnung", "Offene Punkte", "Unsicherheiten"
]);
var extractedThema          = extractEinordnungValue(summaryMessage, "Thema");
var extractedBetroffene     = extractEinordnungValue(summaryMessage, "Betroffene");
var extractedKosten         = extractEinordnungValue(summaryMessage, "Kosten/Haushalt");
var extractedBuergerwirkung = extractEinordnungValue(summaryMessage, "B\u00fcrgerwirkung");

var extractedOffenePunkte = extractBulletSection(summaryMessage, "Offene Punkte", [
  "Unsicherheiten", "Quelle", "Schlagw\u00f6rter"
]);
var extractedUnsicherheiten = extractBulletSection(summaryMessage, "Unsicherheiten", [
  "Quelle", "Schlagw\u00f6rter"
]);

var mainSummary =
  extractedKurzfassung ||
  $json.summaryText ||
  $json.kurzzusammenfassung ||
  $json.kurzfassung ||
  $json.summary ||
  "";

var thema =
  extractedThema ||
  $json.thema ||
  $json.themes ||
  "";

var betroffene =
  extractedBetroffene ||
  formatValue($json.betroffene) ||
  "B\u00fcrgerinnen und B\u00fcrger, Stadtverwaltung, Rat der Stadt Goslar";

var kosten =
  extractedKosten ||
  $json.kostenHaushalt ||
  $json.kosten ||
  "";

var buergerwirkung =
  extractedBuergerwirkung ||
  $json.buergerwirkung ||
  "";

var offenePunkte =
  extractedOffenePunkte.length
    ? extractedOffenePunkte.map(cleanListItem).filter(Boolean)
    : parseArrayLike($json.offenePunkte);

var unsicherheiten =
  extractedUnsicherheiten.length
    ? extractedUnsicherheiten.map(cleanListItem).filter(Boolean)
    : parseArrayLike($json.unsicherheiten || $json.unsicherheitenSummary);

var wordpressTitle = (function() {
  var cleaned = cleanTitle(title);
  var numberAtStart = new RegExp(
    '^\\s*' +
    vorgangsnummer.replace('/', '\\s*\\/\\s*').replace('-', '\\s*-\\s*') +
    '\\s*[-–—:]?\\s*',
    'i'
  );
  var titleWithoutNumber = cleaned.replace(numberAtStart, '').trim();
  return vorgangsnummer + ' – ' + (titleWithoutNumber || cleaned);
})();
var wordpressExcerpt = firstSentences(mainSummary, 2, 320);
var wordpressSlug    = slugify(vorgangsnummer + " " + (thema || wordpressTitle));

var whyImportant =
  buergerwirkung ||
  "Die Vorlage kann Auswirkungen auf B\u00fcrgerinnen und B\u00fcrger, Verwaltungshandeln oder politische Entscheidungen in Goslar haben.";

// BUG 5 BEHOBEN: href-Zeile - Anf\u00fchrungszeichen um den href-Wert jetzt korrekt escaped

// ── Vorgangskette-Abschnitt für WordPress (nur bei Folgevorgängen) ───────────
// Öffentlich werden nur die inhaltlichen Beziehungen gezeigt.
// Technische Meldungen zur Textextraktion gehören nicht in den Beitrag.
var vorgangsketteHtmlBlock = '';

if ($json.istFolgevorgang === true || String($json.istFolgevorgang || '').trim() === 'true') {
  var ketteDetails = Array.isArray($json.vorgangsketteDetails) ? $json.vorgangsketteDetails : [];
  var ketteFehlend = Array.isArray($json.fehlendeVorherigeVorgaenge) ? $json.fehlendeVorherigeVorgaenge : [];
  var ketteStamm = String($json.stammVorgangsnummer || '').trim();
  var gefundeneVorgaenge = ketteDetails.filter(function(d) { return d && d.gefunden; });

  var html = '<h2>Bezug zu vorherigen Vorgängen</h2>\n';
  html += '<p>Dieser Vorgang gehört zur Vorgangskette <strong>' + esc(ketteStamm) + '</strong>.</p>\n';

  if (gefundeneVorgaenge.length > 0) {
    html += '<ul>\n';
    for (var ki = 0; ki < gefundeneVorgaenge.length; ki++) {
      var d = gefundeneVorgaenge[ki];
      var rollenText = d.istStammvorgang ? 'Ausgangsvorgang' : 'vorheriger Folgevorgang';
      var sichtbarerText = String(d.vorgangsnummer || '').trim();
      var chainTitle = cleanTitle(d.title || '');
      if (chainTitle) {
        var vnPrefixRe = new RegExp('^\\s*' + sichtbarerText.replace(/[\\^$.*+?()[\]{}|]/g, '\\$&') + '\\s*[-–—:]?\\s*', 'i');
        chainTitle = chainTitle.replace(vnPrefixRe, '').trim();
      }
      if (chainTitle) sichtbarerText += ' – ' + chainTitle;

      var chainLink = String(d.wordpressPostLink || '').trim() || String(d.allrisUrl || '').trim();
      var chainLinkIsInternal = !!String(d.wordpressPostLink || '').trim();
      if (chainLink) {
        var chainLinkAttrs = chainLinkIsInternal ? '' : ' target="_blank" rel="noopener noreferrer"';
        html += '  <li><a href="' + attrEsc(chainLink) + '"' + chainLinkAttrs + '>' + esc(sichtbarerText) + '</a> (' + esc(rollenText) + ')</li>\n';
      } else {
        html += '  <li>' + esc(sichtbarerText) + ' (' + esc(rollenText) + ')</li>\n';
      }
    }
    html += '</ul>\n';
  } else if (ketteStamm) {
    html += '<p>Der Ausgangsvorgang wird unter der Nummer <strong>' + esc(ketteStamm) + '</strong> geführt.</p>\n';
  }

  if (ketteFehlend.length > 0) {
    html += '<p>Ein Teil der früheren Vorgänge war zum Zeitpunkt der Erstellung noch nicht verfügbar.</p>\n';
  }

  vorgangsketteHtmlBlock = html;
}

var wordpressContent = [
  "<p><strong>Vorgangsnummer:</strong> " + esc(vorgangsnummer) + "</p>",
  "",
  ...(vorgangsketteHtmlBlock ? [vorgangsketteHtmlBlock] : []),
  "",
  "<h2>Kurzzusammenfassung</h2>",
  paragraphHtml(mainSummary),
  "",
  "<h2>Warum ist das wichtig?</h2>",
  "<p>" + esc(whyImportant) + "</p>",
  "",
  "<h2>Fakten zur Vorlage</h2>",
  "<ul>",
  "  <li><strong>Vorgangsnummer:</strong> " + esc(vorgangsnummer) + "</li>",
  "  <li><strong>Thema:</strong> " + esc(thema || "Keine eindeutige Themenangabe vorhanden.") + "</li>",
  "  <li><strong>Betroffene:</strong> " + esc(betroffene) + "</li>",
  "  <li><strong>Kosten/Haushalt:</strong> " + esc(kosten || "Keine konkreten Kostenangaben im Kurztext benannt.") + "</li>",
  "</ul>",
  "",
  "<h2>Offene Fragen</h2>",
  listHtml(offenePunkte, "Keine offenen Fragen im Kurztext benannt."),
  "",
  "<h2>Unsicherheiten</h2>",
  listHtml(unsicherheiten, "Keine besonderen Unsicherheiten im Kurztext benannt."),
  "",
  "<h2>Quelle</h2>",
  "<p><a href=\"" + attrEsc(link) + "\" target=\"_blank\" rel=\"noopener noreferrer\">Vorlage im ALLRIS der Stadt Goslar \u00f6ffnen</a></p>",
  ""
].join("\n").trim();

if (!wordpressTitle) {
  throw new Error("wordpressTitle fehlt");
}

if (!mainSummary) {
  throw new Error("Kurzzusammenfassung fehlt: Weder summaryMessage noch kurzfassung/summary enthalten verwertbaren Text.");
}

if (!wordpressContent.includes("<h2>Kurzzusammenfassung</h2>")) {
  throw new Error("WordPress-Content enth\u00e4lt keine Kurzzusammenfassung.");
}

if (wordpressContent.includes('"msgtype"')) {
  throw new Error("Matrix-JSON wurde versehentlich in den WordPress-Content \u00fcbernommen.");
}

var combinedTagText = [
  title,
  vorgangsnummer,
  thema,
  betroffene,
  kosten,
  buergerwirkung,
  mainSummary,
  offenePunkte.join(" "),
  unsicherheiten.join(" ")
].join(" ");

var wordpressTags = uniqueTags(
  topicTagsFromText(combinedTagText)
);

var outputJson = Object.assign({}, $json, {
  wordpressTitle:   wordpressTitle,
  wordpressSlug:    wordpressSlug,
  wordpressExcerpt: wordpressExcerpt,
  wordpressContent: wordpressContent,
  wordpressTags:    wordpressTags
});

return { json: outputJson };

// Restore Loop Context nach WordPress – stellt Vorgangsdaten nach WordPress-API wieder her.
// Modus: Run Once for Each Item

const response = $json || {};

function getNodeJson(nodeName) {
  try {
    const arr = $(nodeName).all(0, $runIndex);
    if (Array.isArray(arr) && arr.length) return arr[0]?.json || {};
  } catch (e) {}
  try { return $(nodeName).first()?.json || {}; } catch (e) {}
  try { return $(nodeName).item?.json || {}; } catch (e) {}
  return {};
