function termsFromText(text) {
  const normalized = normText(text).replace(/[^a-z0-9\/\- ]+/g, ' ');
  const raw = normalized.split(/\s+/).map(s => s.trim()).filter(Boolean);
  const out = [];
  for (const token of raw) {
    if (token.length < 5 && !/^b\d{2,4}$/.test(token)) continue;
    if (STOP.has(token)) continue;
    if (/^20\d{2}$/.test(token)) continue;
    out.push(token);
  }
  return Array.from(new Set(out)).slice(0, 80);
}

