function detectClusters(text) {
  const t = normText(text);
  const found = [];
  for (const c of CLUSTERS) {
    const hitTerms = [];
    for (const term of c.terms) {
      const nt = normText(term);
      if (nt && t.includes(nt)) hitTerms.push(term);
    }
    if (hitTerms.length > 0) {
      found.push({ id: c.id, label: c.label, hitTerms: Array.from(new Set(hitTerms)).slice(0, 8) });
    }
  }
  return found;
}

function intersectClusters(a, b) {
  const bMap = new Map(b.map(x => [x.id, x]));
  return a.filter(x => bMap.has(x.id)).map(x => ({
    id: x.id,
    label: x.label,
    currentTerms: x.hitTerms,
    candidateTerms: bMap.get(x.id).hitTerms
  }));
}

function extractSubjects(obj) {
  const out = new Map();
  function add(displayText) {
    const disp = safe(displayText);
    if (!disp) return;
    const n = normText(disp);
    if (n && n.length >= 4 && !out.has(n)) out.set(n, disp);
  }
  function addBetroffenePhrase(phrase) {
    const text = safe(phrase);
    if (!text) return;
    // Zusammengesetzte Betroffene-Phrasen wie "Anwohner der Rammelsberger Straße"
    // zusätzlich in ihren atomaren Kern ("Anwohner") aufteilen - kurze, konkrete
    // Tags statt langer Fließtext-Phrasen. Die Straße selbst wird bereits separat
    // über streetRe aus Titel/Thema erkannt.
    add(text);
    const head = text.split(/\s+(?:der|des|von|vom|in|im|an|am|bei)\s+/i)[0].trim();
    if (head && head !== text) add(head);
  }
  for (const b of parseArray(obj.betroffene)) addBetroffenePhrase(b);
  const scanText = [obj.title, obj.thema, obj.themes].map(safe).filter(Boolean).join(' ');
  const streetRe = /\b[A-ZÄÖÜ][a-zäöüß]+(?:straße|strasse|weg|platz|allee|ring|damm|ufer)\b/gi;
  let m;
  while ((m = streetRe.exec(scanText)) !== null) add(m[0]);
  const roadRe = /\b[BLK]\d{2,4}(?:-\d+)?\b/g;
  while ((m = roadRe.exec(scanText)) !== null) add(m[0]);
  const properRe = /\b(?:[A-ZÄÖÜ][a-zäöüß]{2,}\s+){1,4}(?:[A-ZÄÖÜ][a-zäöüß]{2,}|GmbH|e\.V\.|AG|mbH)\b/g;
  while ((m = properRe.exec(scanText)) !== null) {
    if (m[0].trim().split(/\s+/).length >= 2) add(m[0]);
  }
  return out;
}

