const candidates = [];
for (const row of rows) {
  const link = safe(row.wordpressPostLink);
  const key = safe(row.vorgangKey);
  const vn = safe(row.vorgangsnummer);
  if (!link) continue;
  if (key && currentKey && key === currentKey) continue;
  if (vn && currentVn && vn === currentVn) continue;
  if (!truthy(row.wordpressPosted) && !link) continue;

  const text = compactText(row);
  if (!text) continue;

  const candTerms = termsFromText(text);
  const shared = candTerms.filter(t => currentTermSet.has(t));

  const candClusters = detectClusters(text);
  const sharedClusters = intersectClusters(currentClusters, candClusters);

  const candSubjects = extractSubjects(row);
  const sharedSubjects = Array.from(candSubjects.keys()).filter(s => currentSubjects.has(s));

  const candBase = baseVorgangsnummer(vn);
  const candStamm = safe(row.stammVorgangsnummer || candBase);
  const sameChain =
    !!(currentBase && candBase && currentBase === candBase) ||
    !!(currentStamm && candStamm && currentStamm === candStamm && currentStamm !== currentVn);

  let score = 0;
  if (sameChain) score += 60;
  score += sharedClusters.length * 18;
  score += sharedSubjects.length * 25;
  score += Math.min(shared.length, 8);

  // Kandidaten werden nur durchgelassen, wenn entweder eine echte Vorgangskette,
  // ein enger Themencluster, ein gemeinsames konkretes Subjekt (Objekt/Ort/Organisation)
  // oder mehrere starke gemeinsame Begriffe vorliegen. Der Subjekt-Abgleich ist bewusst
  // unabhängig von der festen Cluster-Liste, damit auch künftige, noch unbekannte Themen
  // über gleiche Subjekte als Kandidaten erkannt werden.
  if (!sameChain && sharedClusters.length === 0 && sharedSubjects.length === 0 && shared.length < 4) continue;
  if (score < 4) continue;

  candidates.push({
    vorgangKey: key,
    vorgangsnummer: vn,
    title: safe(row.title),
    wordpressPostLink: link,
    wordpressPostId: safe(row.wordpressPostId),
    wordpressSlug: safe(row.wordpressSlug),
    thema: safe(row.thema || row.themes),
    buergerwirkung: safe(row.buergerwirkung),
    betroffene: parseArray(row.betroffene).slice(0, 8),
    offenePunkte: parseArray(row.offenePunkte).slice(0, 6),
    summaryText: safe(row.summaryText).slice(0, 900),
    sharedTerms: shared.slice(0, 12),
    sharedClusters: sharedClusters.slice(0, 4),
    sharedSubjects: sharedSubjects.slice(0, 8),
    currentClusters: currentClusters.map(c => c.label).slice(0, 8),
    candidateClusters: candClusters.map(c => c.label).slice(0, 8),
    sameVorgangskette: sameChain,
    prefilterScore: score
  });
}

candidates.sort((a, b) => {
  if (a.sameVorgangskette !== b.sameVorgangskette) return a.sameVorgangskette ? -1 : 1;
  const aStrong = (Array.isArray(a.sharedSubjects) ? a.sharedSubjects.length : 0) + (Array.isArray(a.sharedClusters) ? a.sharedClusters.length : 0);
  const bStrong = (Array.isArray(b.sharedSubjects) ? b.sharedSubjects.length : 0) + (Array.isArray(b.sharedClusters) ? b.sharedClusters.length : 0);
  if (aStrong !== bStrong) return bStrong - aStrong;
  return (b.prefilterScore || 0) - (a.prefilterScore || 0);
});

