  for (const r of related) {
    const labelParts = [];
    if (r.vorgangsnummer) labelParts.push(r.vorgangsnummer);
    if (r.title) labelParts.push(r.title);
    const label = labelParts.join(' – ') || 'Verwandter Beitrag';
    relatedBlock += '  <li><a href="' + attrEsc(r.wordpressPostLink) + '">' + esc(label) + '</a>';
    if (r.reason) relatedBlock += '<br><small>' + esc(r.reason) + '</small>';
    relatedBlock += '</li>\n';
  }
  relatedBlock += '</ul>\n';

  if (content.includes('<h2>Quelle</h2>')) {
    content = content.replace('<h2>Quelle</h2>', relatedBlock + '\n<h2>Quelle</h2>');
  } else {
    content = (content + '\n\n' + relatedBlock).trim();
  }
}

return {
  json: {
    ...current,
    wordpressContent: content,
    relatedWordpressPostsJson: JSON.stringify(related),
    relatedTopicLabel,
    relatedCheckedAt: new Date().toISOString(),
    relatedCandidateCount: Number(current._relatedCandidateCount || 0),
    relatedLinksAdded: related.length,
    relatedParseError: parseError
  }
};

// Ermittle fehlende Tags – vergleicht wordpressTags (aus Code in JavaScript) mit den
// bereits existierenden WordPress-Tags und trennt in bereits vorhandene Tag-IDs und
// noch anzulegende Tag-Namen.
// WICHTIG: läuft als Run Once for All Items und holt den Beitrags-Kontext bewusst über
// eine Node-Referenz auf 'Parse Related WP JSON' statt über $input - der Such-Node
// 'HTTP Suche WP Tags' liefert ein JSON-Array zurück, das n8n mögicherweise in mehrere
// Items (ein Item pro Tag) aufsplittet; damit dieser Node trotzdem nur einmal pro
// Vorgang läuft und den korrekten Kontext behält, wird $input nur für die Tag-Liste
// verwendet, nie für den Beitrags-Kontext.

const current = $('Parse Related WP JSON').first().json;
const wpTags = Array.isArray(current.wordpressTags) ? current.wordpressTags : [];

function norm(v) { return String(v || '').trim().toLowerCase(); }

const rawExisting = $input.all().map(i => i.json);
let existingList = rawExisting;
if (rawExisting.length === 1 && Array.isArray(rawExisting[0])) {
  existingList = rawExisting[0];
}

const existingByName = new Map();
for (const t of existingList) {
  if (t && t.name) existingByName.set(norm(t.name), t.id);
}

const resolvedTagIds = [];
const missingTagNames = [];
const seen = new Set();

for (const rawName of wpTags) {
  const name = String(rawName || '').trim();
  if (!name) continue;
  const n = norm(name);
  if (seen.has(n)) continue;
  seen.add(n);
  if (existingByName.has(n)) {
    resolvedTagIds.push(existingByName.get(n));
  } else {
    missingTagNames.push(name);
  }
}

return [{
  json: {
    ...current,
    resolvedTagIds,
    missingTagNames
  }
}];

// Split fehlende Tags – ein Item pro anzulegendem Tag. Falls nichts fehlt, wird ein
// Sentinel-Item durchgereicht, damit die Kette danach nie mit 0 Items weiterläuft
// (sonst würde 'Create a post' für diesen Beitrag gar nicht mehr ausgeführt).
const current = $input.first().json;
const missing = Array.isArray(current.missingTagNames) ? current.missingTagNames : [];

if (missing.length === 0) {
  return [{ json: { tagName: '', isSentinel: true } }];
}

return missing.map(name => ({ json: { tagName: name, isSentinel: false } }));

// Baue finale Tag-Liste – holt den ursprünglichen Beitrags-Kontext von 'Ermittle
// fehlende Tags' zurück und ergänzt die neu angelegten Tag-IDs um die bereits
// vorhandenen. Läuft als Run Once for All Items, da hier mehrere Items (ein Item pro
// angelegtem Tag bzw. das Sentinel-Item) wieder zu einem einzigen Beitrags-Item
// zusammengeführt werden müssen.
// Fallback: wenn ein Tag zwischen Suche und Anlage von woanders bereits angelegt
// wurde, antwortet WordPress mit einem term_exists-Fehler statt der Tag-ID - in
// diesem Fall wird die vorhandene ID aus der Fehlerantwort extrahiert, statt den
// Tag stillschweigend zu verlieren.
const original = $('Ermittle fehlende Tags').first().json;
const resolvedTagIds = Array.isArray(original.resolvedTagIds) ? original.resolvedTagIds : [];

function extractTagId(j) {
  if (!j) return null;
  if (j.id) return j.id;
  if (j.body && j.body.id) return j.body.id;
  if (j.data && j.data.term_id) return j.data.term_id;
  if (j.error && j.error.data && j.error.data.term_id) return j.error.data.term_id;
  return null;
}

const newTagIds = [];
for (const item of $input.all()) {
  const id = extractTagId(item.json || {});
  if (id) newTagIds.push(id);
}

return [{
  json: {
    ...original,
    wordpressTagIds: [...new Set([...resolvedTagIds, ...newTagIds])]
  }
}];
